Explain the difference between value and pointer receivers in this Go code and why only one of the increments persists:

```go
type Counter struct{ n int }

func (c Counter) IncVal()  { c.n++ }
func (c *Counter) IncPtr() { c.n++ }

func main() {
	c := Counter{}
	c.IncVal()
	c.IncPtr()
	fmt.Println(c.n)
}
```

